const loadMap=()=>{let center=getCenter(data);let position=new naver.maps.LatLng(data.lat,data.lng);let map=new naver.maps.Map('map',{center:position,zoom:15});let markers=[],marker;for(let row of data){position=new naver.maps.LatLng(row.lat,row.lng);marker=new naver.maps.Marker({map:map,position:position,});};}
const getCenter=(coordinates)=>{let totalLat=0;let totalLng=0;coordinates.forEach(coord=>{totalLat+=coord.lat;totalLng+=coord.lng;});const centerLat=totalLat/coordinates.length;const centerLng=totalLng/coordinates.length;return{lat:centerLat,lng:centerLng};}
document.addEventListener("DOMContentLoaded",()=>{if(data&&window.location.pathname.startsWith("/info")){loadMap()}});